#include <iostream>
#include <vector>
using namespace std;
class ListNode { int val; ListNode* next; };
class Solution { public: int solve(ListNode* head) { int count = 0; while (head) { count++; head = head->next; } return count; } };
int main() {
    Solution solution;
    ListNode* head = new ListNode(1);
    head->next = new ListNode(2);
    head->next->next = new ListNode(3);
    head->next->next->next = new ListNode(4);
    head->next->next->next->next = new ListNode(5);
    cout << solution.solve(head) << endl;
    return 0;
}
